### **3. BUILD & BUNDLING ARCHITECTURE**

#### **Extension Host Bundling** — [esbuild.js](esbuild.js)

```javascript
const esbuild = require('esbuild')
const production = process.argv.includes('--production')
const watch = process.argv.includes('--watch')

const esbuildProblemMatcherPlugin = {
  name: 'esbuild-problem-matcher',
  setup(build) {
    build.onStart(() => console.log('[watch] build started'))
    build.onEnd((result) => {
      result.errors.forEach(({ text, location }) => {
        console.error(`✘ [ERROR] ${text}`)
        console.error(`    ${location.file}:${location.line}:${location.column}:`)
      })
      console.log('[watch] build finished')
    })
  },
}

async function main() {
  const ctx = await esbuild.context({
    entryPoints: ['src/extension.ts'],
    bundle: true,
    format: 'cjs',
    minify: production,
    sourcemap: !production,
    sourcesContent: false,
    platform: 'node',
    outfile: 'dist/extension.js',
    external: ['vscode'],
    logLevel: 'silent',
    plugins: [esbuildProblemMatcherPlugin],
  })
  if (watch) {
    await ctx.watch()
  } else {
    await ctx.rebuild()
    await ctx.dispose()
  }
}

main().catch((e) => {
  console.error(e)
  process.exit(1)
})
```

**Key config:**
- Bundles only `src/extension.ts` → `dist/extension.js` (CommonJS, Node platform)
- Marks `vscode` as external (loaded by VS Code runtime)
- Production: minified, no sourcemaps; Dev: sourcemaps included

