### **4. EXTENSION ACTIVATION & COMMAND REGISTRATION**

#### **[src/extension.ts](src/extension.ts) — Main Entry Point**

```typescript
export async function activate(context: vscode.ExtensionContext) {
	logger.info("Wandelbots NOVA extension activating...");

	// ==============================
	// Wandelbots NOVA Viewer (Sidebar)
	// ==============================
	const provider = new WandelbotsNovaViewerProvider(context.extensionUri, context.globalState);

	// Register the custom view provider
	context.subscriptions.push(vscode.window.registerWebviewViewProvider(VIEWER_ID, provider));

	// Register command to open the webview
	context.subscriptions.push(
		vscode.commands.registerCommand(COMMAND_OPEN_NOVA_VIEWER, async () => {
			provider.selectTab(1);
			await provider.forceReveal();
		}),
	);

	// Register command to refresh the webview
	context.subscriptions.push(
		vscode.commands.registerCommand(COMMAND_REFRESH_NOVA_VIEWER, async () => {
			await provider.hardRefresh();
			vscode.window.showInformationMessage("Wandelbots NOVA Viewer refreshed");
		}),
	);

	// ==============================
	// Wandelbots NOVA CodeLens
	// ==============================
	const novaCodeLensProvider = new NovaCodeLensProvider();

	context.subscriptions.push(
		vscode.languages.registerCodeLensProvider({ language: "python" }, novaCodeLensProvider),
	);

	// Register command to run Nova program
	context.subscriptions.push(
		vscode.commands.registerCommand(
			COMMAND_RUN_NOVA_PROGRAM,
			async (uri, functionName, _line, _programId) => {
				await runNovaProgram(uri, functionName, false);
			},
		),
	);

	// Register command to debug Nova program
	context.subscriptions.push(
		vscode.commands.registerCommand(
			COMMAND_DEBUG_NOVA_PROGRAM,
			async (uri, functionName, _line, _programId) => {
				await runNovaProgram(uri, functionName, true);
			},
		),
	);

	// Register Program Debugger sidebar view provider
	const programDebuggerProvider = new ProgramDebuggerViewProvider(context.extensionUri);
	context.subscriptions.push(
		vscode.window.registerWebviewViewProvider(PROGRAM_DEBUGGER_VIEW_ID, programDebuggerProvider),
	);

	// Setup Python script monitoring (triggers auto-refresh on execution)
	setupPythonScriptMonitoring(context, provider);
}
```

**Activation flow:**
1. Creates `WandelbotsNovaViewerProvider` and `ProgramDebuggerViewProvider` (both implement `vscode.WebviewViewProvider`)
2. Registers them with `registerWebviewViewProvider()` — VS Code calls their `resolveWebviewView()` methods when views become visible
3. Registers 15+ commands, each mapped to handlers in the extension or passed through to webview
4. Sets up Python script monitoring (watches for `nova.rrd` file changes, triggers webview refresh)

