### **5. WEBVIEW PROVIDERS & UI PANELS**

#### **[src/viewer.ts](src/viewer.ts) — Main Sidebar Webview**

```typescript
export class WandelbotsNovaViewerProvider implements vscode.WebviewViewProvider {
	private _view?: vscode.WebviewView;
	private _pendingInitialTab: number | undefined;
	private _openPanels: Map<string, vscode.WebviewPanel> = new Map(); // Editor panels
	private _pendingPanelMessages: Map<string, unknown[]> = new Map();
	private _readyPanels: Set<string> = new Set();

	constructor(
		private readonly _extensionUri: vscode.Uri,
		private readonly _globalState: vscode.Memento,
	) {}

	// Called when sidebar view becomes visible
	async resolveWebviewView(
		webviewView: vscode.WebviewView,
		_context: vscode.WebviewViewResolveContext,
		_token: vscode.CancellationToken,
	): Promise<void> {
		this._view = webviewView;

		webviewView.webview.options = {
			enableScripts: true,
			localResourceRoots: [this._extensionUri],
		};

		// Handle messages from webview
		webviewView.webview.onDidReceiveMessage(
			async (message: { command: string; url?: string }) => {
				switch (message.command) {
					case "refresh":
						console.log("Webview requested refresh");
						await this.hardRefresh();
						break;
					case "ready":
						console.log("Webview is ready");
						break;
					case "openTouchUpPanel":
						vscode.commands.executeCommand(COMMAND_OPEN_TOUCH_UP_PANEL);
						break;
					case "open3DPathViewer":
						vscode.commands.executeCommand(COMMAND_OPEN_3D_PATH_VIEWER);
						break;
					case "fetchRequest":
						await handleFetchProxy(message as any, webviewView.webview);
						break;
					case "saveFile":
						await handleSaveFile(message.fileName, message.content, this._globalState);
						break;
					// ... more handlers
				}
			},
		);

		// Show loading screen first
		webviewView.webview.html = this._getLoadingHtml();

		try {
			const url = await getConfiguredUrl();
			webviewView.webview.html = this._getReactAppHtml(webviewView.webview);
		} catch (error) {
			webviewView.webview.html = this._getErrorHtml(error);
		}
	}

	private _getReactAppHtml(webview: vscode.Webview): string {
		const fs = require("node:fs");
		const indexPath = vscode.Uri.joinPath(this._extensionUri, "app", "dist", "index.html");
		let html: string = fs.readFileSync(indexPath.fsPath, "utf8");

		const distRoot = vscode.Uri.joinPath(this._extensionUri, "app", "dist");
		const distWebviewRoot = webview.asWebviewUri(distRoot);

		// Security: CSP + nonce
		const nonce = getNonce();
		const csp = `
      default-src 'none';
      img-src ${webview.cspSource} blob: data:;
      style-src ${webview.cspSource} 'unsafe-inline';
      font-src ${webview.cspSource};
      script-src 'nonce-${nonce}' 'wasm-unsafe-eval';
      worker-src ${webview.cspSource} blob:;
      connect-src ${webview.cspSource} https: http: ws: wss: blob: data:;
    `.replace(/\n/g, " ");

		// Inject config into HTML
		const configScript = `<script nonce="${nonce}">window.__NOVA_CONFIG__=${JSON.stringify({
			novaApi: getNovaApiAddress(),
			accessToken: getAccessToken(),
			cellName: getCellName(),
			natsBroker: getNatsBroker(),
			initialTab: this._pendingInitialTab,
		})};</script>`;

		html = html
			.replace(/<head>/i, `<head><base href="${distWebviewRoot.toString()}/">
           <meta http-equiv="Content-Security-Policy" content="${csp}">`)
			.replace(/<script /g, `<script nonce="${nonce}" `)
			.replace(/<\/head>/i, `${configScript}</head>`);

		return html;
	}

	// Create standalone editor panels (Touch-Up, Data Sharing, etc.)
	createEditorPanel(pageId: string, title: string): vscode.WebviewPanel {
		// Singleton: reuse existing panel
		const existing = this._openPanels.get(pageId);
		if (existing) {
			existing.reveal(vscode.ViewColumn.One);
			return existing;
		}

		const panel = vscode.window.createWebviewPanel(
			`wandelbots-nova-${pageId}`,
			title,
			vscode.ViewColumn.One,
			{
				enableScripts: true,
				localResourceRoots: [this._extensionUri],
				retainContextWhenHidden: true,
			},
		);

		// Load same React app HTML but inject `initialPage: pageId` in config
		// (App.tsx routes to correct page based on config.initialPage)
		const fs = require("node:fs");
		const indexPath = vscode.Uri.joinPath(this._extensionUri, "app", "dist", "index.html");
		let html: string = fs.readFileSync(indexPath.fsPath, "utf8");

		// ... (same CSP + config injection pattern as resolveWebviewView)

		panel.webview.html = html;

		// Handle messages
		panel.webview.onDidReceiveMessage(async (message: { command: string }) => {
			switch (message.command) {
				case "ready":
					this._readyPanels.add(pageId);
					// Flush queued messages
					for (const msg of (this._pendingPanelMessages.get(pageId) || [])) {
						panel.webview.postMessage(msg);
					}
					break;
				case "fetchRequest":
					await handleFetchProxy(message as any, panel.webview);
					break;
				// ... more handlers
			}
		});

		this._openPanels.set(pageId, panel);
		panel.onDidDispose(() => {
			this._openPanels.delete(pageId);
			this._readyPanels.delete(pageId);
		});

		return panel;
	}

	// Create 3D Path Viewer (Rerun iframe, not React)
	async createRerunPanel(): Promise<vscode.WebviewPanel> {
		const existing = this._openPanels.get("3d-path-viewer");
		if (existing) {
			existing.reveal(vscode.ViewColumn.One);
			return existing;
		}

		const rerunUrl = await getConfiguredUrl();
		const panel = vscode.window.createWebviewPanel(
			"wandelbots-nova-3d-path-viewer",
			"3D Path Viewer",
			vscode.ViewColumn.One,
			{ enableScripts: true, retainContextWhenHidden: true },
		);

		// Inject iframe pointing to Rerun server
		panel.webview.html = `
      <!DOCTYPE html>
      <html>
      <head><meta http-equiv="Content-Security-Policy" content="frame-src *;">
      <style>html, body { margin: 0; height: 100%; } iframe { width: 100%; height: 100%; }</style>
      </head>
      <body>
        <iframe src="${rerunUrl}"></iframe>
        <script>
          window.addEventListener('message', (e) => {
            if (e.data?.command === 'refresh') { location.reload(); }
          });
        </script>
      </body>
      </html>
    `;

		this._openPanels.set("3d-path-viewer", panel);
		panel.onDidDispose(() => this._openPanels.delete("3d-path-viewer"));
		return panel;
	}

	// Refresh sidebar view via postMessage (fastest)
	async refreshView(): Promise<void> {
		if (this._view) {
			this._view.webview.postMessage({ command: "refresh", timestamp: Date.now() });
		}
	}

	// Hard refresh (reload HTML)
	async hardRefresh(): Promise<void> {
		if (this._view) {
			this._view.webview.html = this._getReactAppHtml(this._view.webview);
		}
		// Also refresh all open editor panels...
	}
}
```

**Key patterns:**
- **Webview lifecycle**: `registerWebviewViewProvider()` → `resolveWebviewView()` called when view becomes visible
- **Config injection**: Reads from VS Code settings, injects into `window.__NOVA_CONFIG__` script tag
- **Security**: CSP with nonce, `localResourceRoots` restricts file access
- **Editor panels**: Singleton pattern (one per page type), can reuse same React app with different `initialPage` config
- **Messaging**: bidirectional `postMessage()` / `onDidReceiveMessage()` for commands
- **3D Path Viewer**: Special case — iframe pointing to Rerun server, not React app

