```typescript
export class ProgramDebuggerViewProvider implements vscode.WebviewViewProvider {
	private _view?: vscode.WebviewView;
	private _programId?: string;
	private _isReady = false;
	private _pendingMessages: unknown[] = [];

	async reveal(): Promise<void> {
		// Set context to make view visible
		await vscode.commands.executeCommand(
			"setContext",
			"wandelbots-nova.programDebuggerVisible",
			true,
		);

		// Toggle container open
		await vscode.commands.executeCommand(
			`workbench.view.extension.${PROGRAM_DEBUGGER_VIEW_ID}`,
		);

		if (this._view) {
			this._view.show?.(true);
		}
	}

	async resolveWebviewView(
		webviewView: vscode.WebviewView,
		_context: vscode.WebviewViewResolveContext,
		_token: vscode.CancellationToken,
	): Promise<void> {
		this._view = webviewView;

		webviewView.webview.options = {
			enableScripts: true,
			localResourceRoots: [this._extensionUri],
		};

		webviewView.webview.onDidReceiveMessage(
			async (message: { command: string }) => {
				switch (message.command) {
					case "ready":
						this._isReady = true;
						// Flush pending messages (e.g., setProgramId before ready)
						for (const msg of this._pendingMessages) {
							webviewView.webview.postMessage(msg);
						}
						this._pendingMessages = [];
						break;
					case "stopNovaProgram":
						stopRunningNovaProgram();
						break;
					case "reloadNovaProgram":
						if (this._lastRunArgs) {
							const { uri, functionName, programId } = this._lastRunArgs;
							vscode.commands.executeCommand(
								COMMAND_RELOAD_NOVA_PROGRAM,
								uri,
								functionName,
								programId,
							);
						}
						break;
					case "fetchRequest":
						await handleFetchProxy(message as any, webviewView.webview);
						break;
				}
			},
		);

		// Load same React app but with initialPage: "program-debugger"
		const fs = require("node:fs");
		const indexPath = vscode.Uri.joinPath(this._extensionUri, "app", "dist", "index.html");
		let html: string = fs.readFileSync(indexPath.fsPath, "utf8");
		// ... (same injection pattern)
		webviewView.webview.html = html;
	}
}
```

