```typescript
import { Canvas } from "@react-three/fiber";
import { Bounds, OrbitControls } from "@react-three/drei";
import {
	MotionGroupVisualizer,
	PresetEnvironment,
} from "@wandelbots/wandelbots-js-react-components/3d";
import { getNovaConfig } from "../utils/vscodeApi";

/**
 * Live 3D visualization with solid robot, ghost robots (blue=current, green=stored),
 * and waypoint marker.
 */
export function RobotScene({
	connectedMotionGroup,
	ghostJoints,
	storedJoints,
	markerPose,
}: RobotSceneProps) {
	// Fetch robot GLB from NOVA API (cached)
	const modelUrl = useMemo(
		() => getModelUrl(connectedMotionGroup.modelFromController),
		[connectedMotionGroup.modelFromController],
	);

	const solidState = connectedMotionGroup.rapidlyChangingMotionState;
	const blueGhostState = useMemo(
		() => (ghostJoints ? withGhostJoints(solidState, ghostJoints) : null),
		[solidState, ghostJoints],
	);
	const greenGhostState = useMemo(
		() => (storedJoints ? withGhostJoints(solidState, storedJoints) : null),
		[solidState, storedJoints],
	);

	return (
		<Canvas>
			<Suspense fallback={null}>
				<Bounds fit clip="auto">
					<OrbitControls autoRotate />
					<PresetEnvironment />

					{/* Solid robot */}
					<MotionGroupVisualizer
						connectedMotionGroup={{ ...connectedMotionGroup, modelUrl }}
						color="#ffffff"
					/>

					{/* Blue ghost (current) */}
					{blueGhostState && (
						<MotionGroupVisualizer
							connectedMotionGroup={{
								...connectedMotionGroup,
								rapidlyChangingMotionState: blueGhostState,
								modelUrl,
							}}
							color={GHOST_COLOR}
							opacity={GHOST_OPACITY}
						/>
					)}

					{/* Green ghost (stored) */}
					{greenGhostState && (
						<MotionGroupVisualizer
							connectedMotionGroup={{
								...connectedMotionGroup,
								rapidlyChangingMotionState: greenGhostState,
								modelUrl,
							}}
							color={STORED_COLOR}
							opacity={GHOST_OPACITY}
						/>
					)}

					{/* Waypoint marker (gizmo) */}
					{markerPose && <PoseGizmo pose={markerPose} />}
				</Bounds>
			</Suspense>
		</Canvas>
	);
}

// Fetch GLB from NOVA API, cache by model name
const modelBlobCache = new Map<string, Promise<Blob>>();

function fetchModelBlob(modelFromController: string): Promise<Blob> {
	const cached = modelBlobCache.get(modelFromController);
	if (cached) return cached;

	const promise = (async () => {
		const { novaApi, accessToken } = getNovaConfig();
		const base = (novaApi ?? "").replace(/\/+$/, "");
		const url = `${base}/api/v2/motion-group-models/${encodeURIComponent(
			modelFromController,
		)}/glb`;
		const res = await fetch(url, {
			headers: accessToken ? { Authorization: `Bearer ${accessToken}` } : {},
		});
		if (!res.ok) throw new Error(`Failed to load robot model (${res.status})`);
		return res.blob();
	})();

	promise.catch(() => modelBlobCache.delete(modelFromController));
	modelBlobCache.set(modelFromController, promise);
	return promise;
}
```

**Robot rendering stack:**
- **Three.js**: Core 3D rendering
- **React Three Fiber** (`@react-three/fiber`): React wrapper for Three.js
- **Drei** (`@react-three/drei`): Utilities (OrbitControls, Bounds, etc.)
- **@wandelbots/wandelbots-js-react-components/3d**: Provides `MotionGroupVisualizer` (renders robot from GLTF GLB file) and `PresetEnvironment`
- **GLB models**: Fetched from `{novaApi}/api/v2/motion-group-models/{modelFromController}/glb`
- **Ghost robots**: Separate instances with opacity override, driven by ghost joint positions

#### **[app/src/utils/vscodeApi.ts](app/src/utils/vscodeApi.ts) — VS Code Webview Bridge**

```typescript
import { ofetch } from "ofetch";
import type { NovaWebviewConfig, WebviewToExtensionMessage } from "../types/messages";

interface VsCodeApi {
	postMessage(message: unknown): void;
	getState(): unknown;
	setState(state: unknown): void;
}

let api: VsCodeApi | undefined;

function getApi(): VsCodeApi | undefined {
	if (api) return api;
	try {
		api = (window as any).acquireVsCodeApi?.() as VsCodeApi | undefined;
	} catch {
		// Not running inside a VS Code webview (e.g. Vite dev server)
	}
	return api;
}

/** Send a typed message to the extension host. */
export function postMessageToExtension(message: WebviewToExtensionMessage): void {
	getApi()?.postMessage(message);
}

/**
 * Read Nova configuration.
 * Resolution order: window.__NOVA_CONFIG__ (injected by extension) → import.meta.env (Vite)
 */
export function getNovaConfig(): Partial<NovaWebviewConfig> {
	if (typeof window === "undefined") return {};
	const injected: Partial<NovaWebviewConfig> = (window as any).__NOVA_CONFIG__ ?? {};
	const env = (import.meta as any).env ?? {};
	return {
		novaApi: injected.novaApi || env.VITE_NOVA_API || undefined,
		accessToken: injected.accessToken || env.VITE_ACCESS_TOKEN || undefined,
		cellName: injected.cellName || env.VITE_CELL_NAME || undefined,
		natsBroker: injected.natsBroker || env.VITE_NATS_BROKER || undefined,
		...injected,
	};
}

export async function proxyFetch(url: string, init?: {...}): Promise<{...}> {
	// Direct fetch via ofetch (works in webview with CSP)
	try {
		const res = await ofetch.raw(url, {
			method: (init?.method ?? "GET") as any,
			headers: init?.headers,
			body: init?.body,
			responseType: "text",
			ignoreResponseError: true,
			timeout: init?.timeout ?? 15_000,
		});
		const ok = res.status >= 200 && res.status < 300;
		const bodyText: string = typeof res._data === "string" ? res._data : JSON.stringify(res._data ?? "");
		return {
			ok,
			status: res.status,
			text: () => Promise.resolve(bodyText),
			json: () => Promise.resolve(JSON.parse(bodyText)),
		};
	} catch (error) {
		// Fallback to extension proxy...
	}
}
```

#### **[app/src/config.ts](app/src/config.ts) — Config Resolution**

```typescript
function getConfig() {
	const ls = typeof window !== "undefined" ? window.localStorage : undefined;
	const injected = (typeof window !== "undefined" && (window as any).__NOVA_CONFIG__) || {};
	const env = (import.meta as any).env ?? {};

	const resolve = (key: string, envKey: string, lsKey: string, fallback = ""): string =>
		injected[key] || env[envKey] || ls?.getItem(lsKey) || fallback;

	const prefix = "wandelbots-nova-viewer";

	const novaApi = resolve("novaApi", "VITE_NOVA_API", `${prefix}.novaApi`);
	const cellName = resolve("cellName", "VITE_CELL_NAME", `${prefix}.cellName`, "cell");
	const accessToken = resolve("accessToken", "VITE_ACCESS_TOKEN", `${prefix}.accessToken`);
	const natsBroker = resolve(
		"natsBroker",
		"VITE_NATS_BROKER",
		`${prefix}.natsBroker`,
		"nats://localhost:4222",
	);

	return { novaApi, cellName, accessToken, natsBroker };
}

export const { novaApi, cellName, accessToken, natsBroker } = getConfig();
```

**Resolution order:**
1. `window.__NOVA_CONFIG__` (injected by extension HTML)
2. `import.meta.env.VITE_*` (from `.env` file, Vite dev server)
3. `localStorage` (persisted from settings UI)
4. Fallback defaults

